import * as Enum from "./enum";

export type ThinkingEffort = boolean | "low" | "medium" | "high";

export interface OllamaErrorResponse {
  error: string;
}

/* Type Guard for OllamaErrorResponse */
export function isOllamaErrorResponse(obj: unknown): obj is OllamaErrorResponse {
  if (!obj || typeof obj !== "object") return false;
  return "error" in obj && typeof obj.error === "string";
}

export interface OllamaServer {
  url: string;
  auth?: OllamaServerAuth;
}

export interface OllamaServerAuth {
  mode: Enum.OllamaServerAuthorizationMethod;
  username?: string;
  password?: string;
  token?: string;
}

export interface OllamaApiVersionResponse {
  version: string;
}

export interface OllamaApiGenerateOptionsRequestBody {
  seed?: number;
  numa?: boolean;
  num_ctx?: number;
  num_keep?: number;
  num_batch?: number;
  numgqa?: number;
  num_gpu?: number;
  main_gpu?: number;
  low_vram?: boolean;
  f16_kv?: boolean;
  logits_all?: boolean;
  vocab_only?: boolean;
  use_mmap?: boolean;
  use_mlock?: boolean;
  embedding_only?: boolean;
  rope_frequency_base?: number;
  rope_frequency_scale?: number;
  repeate_last_n?: number;
  repeat_penalty?: number;
  frequency_penalty?: number;
  presence_penalty?: number;
  temperature?: number;
  top_k?: number;
  top_p?: number;
  tfs_z?: number;
  typical_p?: number;
  mirostat?: number;
  mirostat_tau?: number;
  mirostat_eta?: number;
  penalize_newline?: boolean;
  stop?: string[];
  num_thread?: number;
}

export interface OllamaApiGenerateRequestBody {
  model: string;
  prompt?: string;
  suffix?: string;
  system?: string;
  template?: string;
  context?: number[];
  stream?: boolean;
  think?: ThinkingEffort;
  raw?: boolean;
  format?: string;
  images?: string[];
  keep_alive?: string | number;

  options?: OllamaApiGenerateOptionsRequestBody;
}

export interface OllamaApiGenerateStats {
  model: string;
  created_at: string;

  total_duration?: number;
  load_duration?: number;
  prompt_eval_count?: number;
  prompt_eval_duration?: number;
  eval_count?: number;
  eval_duration?: number;

  done: boolean;
  done_reason?: string;
}

/* Type Guard for OllamaApiGenerateStats */
export function isOllamaApiGenerateStats(obj: unknown): obj is OllamaApiGenerateStats {
  if (!obj || typeof obj !== "object") return false;

  const record = obj as Record<string, unknown>;
  return typeof record.model === "string" && typeof record.created_at === "string" && typeof record.done === "boolean";
}

export interface OllamaApiGenerateResponse extends OllamaApiGenerateStats {
  thinking?: string;
  response: string;
  context?: number[];
}

/* Type Guard for OllamaApiGenerateResponse */
export function isOllamaApiGenerateResponse(obj: unknown): obj is OllamaApiGenerateResponse {
  return isOllamaApiGenerateStats(obj) && "response" in obj && typeof obj.response === "string";
}

export interface OllamaApiChatResponse extends OllamaApiGenerateStats {
  message?: OllamaApiChatMessage;
}

/* Type Guard for OllamaApiChatResponse */
export function isOllamaApiChatResponse(obj: unknown): obj is OllamaApiChatResponse {
  return isOllamaApiGenerateStats(obj) && "message" in obj && isOllamaApiChatMessage(obj.message);
}

